import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

describe('sortNotesByUpdatedAt', () => {
  // Mock notes with different updatedAt timestamps
  const mockNotes = [
    { id: '1', title: 'Note 1', updatedAt: '2023-01-03T10:00:00Z' },
    { id: '2', title: 'Note 2', updatedAt: '2023-01-01T10:00:00Z' },
    { id: '3', title: 'Note 3', updatedAt: '2023-01-02T10:00:00Z' },
  ];

  // Import the function being tested
  // Assuming it's exported from a module
  let sortNotesByUpdatedAt: (notes?: any[]) => any[];
  
  beforeEach(async () => {
    const module = await import('./notes');
    sortNotesByUpdatedAt = module.sortNotesByUpdatedAt;
  });

  it('should sort notes by updatedAt in descending order (happy path)', () => {
    const result = sortNotesByUpdatedAt(mockNotes);
    
    // Most recent date should be first
    expect(result[0].id).toBe('1');
    expect(result[0].updatedAt).toBe('2023-01-03T10:00:00Z');
    
    expect(result[1].id).toBe('3');
    expect(result[1].updatedAt).toBe('2023-01-02T10:00:00Z');
    
    expect(result[2].id).toBe('2');
    expect(result[2].updatedAt).toBe('2023-01-01T10:00:00Z');
  });

  it('should handle edge case with notes having identical updatedAt timestamps', () => {
    const notesWithSameTimestamp = [
      { id: '1', title: 'Note A', updatedAt: '2023-01-01T10:00:00Z' },
      { id: '2', title: 'Note B', updatedAt: '2023-01-01T10:00:00Z' },
      { id: '3', title: 'Note C', updatedAt: '2023-01-01T10:00:00Z' },
    ];
    
    const result = sortNotesByUpdatedAt(notesWithSameTimestamp);
    
    expect(result).toHaveLength(3);
    // All notes should still be present
    expect(result.map(n => n.id)).toContain('1');
    expect(result.map(n => n.id)).toContain('2');
    expect(result.map(n => n.id)).toContain('3');
  });

  it('should handle null/empty input gracefully', () => {
    // Test with null
    expect(sortNotesByUpdatedAt(null)).toEqual([]);
    
    // Test with undefined
    expect(sortNotesByUpdatedAt(undefined)).toEqual([]);
    
    // Test with empty array
    expect(sortNotesByUpdatedAt([])).toEqual([]);
    
    // Test with default parameter (no argument passed)
    expect(sortNotesByUpdatedAt()).toEqual([]);
  });
});

