describe('matchesSearchQuery', () => {
  beforeEach(() => {
    // No external dependencies to mock for this function
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('should handle happy path where note contains the query (case‑insensitive)', () => {
    const note = 'Today I learned about Vitest testing framework.';
    const query = 'vitest';
    const result = matchesSearchQuery(note, query);
    expect(result).toBe(true);
  });

  it('should handle edge case with empty query string (should match any note)', () => {
    const note = 'Any content works here.';
    const query = '';
    const result = matchesSearchQuery(note, query);
    // Assuming an empty query matches everything
    expect(result).toBe(true);
  });

  it('should handle null/empty inputs gracefully', () => {
    // null note
    expect(matchesSearchQuery(null as any, 'test')).toBe(false);
    // undefined note
    expect(matchesSearchQuery(undefined as any, 'test')).toBe(false);
    // empty note string
    expect(matchesSearchQuery('', 'test')).toBe(false);

    // null query
    const note = 'Sample note';
    expect(matchesSearchQuery(note, null as any)).toBe(true); // empty query matches
    // undefined query
    expect(matchesSearchQuery(note, undefined as any)).toBe(true);
    // numeric zero as query
    expect(matchesSearchQuery(note, 0 as any)).toBe(true);
  });
});

