import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { countWords } from './countWords';

describe('countWords', () => {
  it('should handle happy path', () => {
    const input = 'Hello world, this is a test.';
    const result = countWords(input);
    expect(result).toBe(6);
  });

  it('should handle edge case', () => {
    const input = '  Leading and trailing   spaces  ';
    const result = countWords(input);
    expect(result).toBe(4);
  });

  it('should handle null/empty', () => {
    const inputs = [null, undefined, '', 0 as any];
    const expected = [0, 0, 0, 0];
    inputs.forEach((input, index) => {
      const result = countWords(input as unknown as string);
      expect(result).toBe(expected[index]);
    });
  });
});